INSERT INTO ledger_entries (
    request_no, transfer_request_id, ledger_account_id, member_id,
    account_type, entry_type, direction, amount, balance_after,
    reserved_balance_after, description
) VALUES (
    #{requestNo}, #{transferRequestId}, #{ledgerAccountId}, #{memberId},
    #{accountType}, #{entryType}, #{direction}, #{amount}, #{balanceAfter},
    #{reservedBalanceAfter}, #{description}
)

mapper.select:
SELECT le.id AS transaction_id, le.entry_type AS transaction_type, le.amount, le.balance_after, le.description, le.created_at, le.request_no AS transfer_no, source_account.account_number AS from_account_number, target_account.account_number AS to_account_number FROM ledger_entries le LEFT JOIN ledger_transfer_requests ltr ON le.transfer_request_id = ltr.id LEFT JOIN ledger_accounts source_account ON ltr.source_account_id = source_account.id LEFT JOIN ledger_accounts target_account ON ltr.target_account_id = target_account.id WHERE le.ledger_account_id = #{ledgerAccountId} AND le.entry_type IN
#{type}
AND le.created_at >= #{fromCreatedAt} AND le.created_at < #{toCreatedAtExclusive}
AND ( le.created_at < #{cursorCreatedAt} OR (le.created_at = #{cursorCreatedAt} AND le.id < #{cursorId}) )
ORDER BY le.created_at DESC, le.id DESC LIMIT #{limit}
